"""SQLAlchemy ORM models — generated by doql."""
from sqlalchemy import Column, String, Integer, Float, Boolean, Text, Date, DateTime, JSON, ForeignKey
from sqlalchemy.orm import relationship
from database import Base


class Instrument(Base):
    __tablename__ = "instruments"

    serial = Column(String(255), unique=True)
    manufacturer = Column(String(255))
    model = Column(String(255))
    category = Column(String(255), nullable=True)
    range_min = Column(String(255), nullable=True)
    range_max = Column(String(255), nullable=True)
    unit = Column(String(255))
    uncertainty_class = Column(String(255), nullable=True)
    owner_organization = Column(String(255), nullable=True)
    last_calibration = Column(Date, nullable=True)
    certificate_valid_until = Column(Date, nullable=True)


class ReferenceStandard(Base):
    __tablename__ = "reference_standards"

    instrument = Column(String(255), ForeignKey("instruments.id"), nullable=True)
    traceability_chain = Column(Text)
    uncertainty_budget = Column(JSON, nullable=True)
    certificate_pdf = Column(String(512))
    valid_until = Column(Date)


class Calibration(Base):
    __tablename__ = "calibrations"

    id = Column(String(36), primary_key=True)
    instrument = Column(String(255), ForeignKey("instruments.id"), nullable=True)
    performed_by = Column(String(255), ForeignKey("operators.id"), nullable=True)
    reviewed_by = Column(String(255), ForeignKey("operators.id"), nullable=True)
    reference_used = Column(String(255), ForeignKey("reference_standards.id"), nullable=True)
    scenario = Column(String(255), nullable=True)
    date = Column(DateTime, nullable=True)
    measurements = Column(JSON, nullable=True)
    uncertainty_calculation = Column(JSON, nullable=True)
    result = Column(String(255), nullable=True)
    certificate_number = Column(String(255), nullable=True)


class Customer(Base):
    __tablename__ = "customers"

    name = Column(String(255))
    address = Column(Text, nullable=True)
    contact_email = Column(String(255), nullable=True)
    vat_id = Column(String(255), nullable=True)
    active = Column(Boolean, nullable=True, default=True)


class CalibrationOrder(Base):
    __tablename__ = "calibration_orders"

    customer = Column(String(255), ForeignKey("customers.id"), nullable=True)
    instruments = Column(String(255), nullable=True)
    received_date = Column(Date, nullable=True)
    due_date = Column(Date, nullable=True)
    priority = Column(String(255), nullable=True)
    status = Column(String(255), nullable=True)
    total_price = Column(String(255), nullable=True)
    invoice_number = Column(String(255), nullable=True)
